{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Withings Measurement Payload",
  "description": "Standardized data schema for Withings Body+ measurements in the Comfortage project.",
  "type": "array",
  "items": {
    "type": "object",
    "properties": {
      "userId": {
        "type": "string",
        "description": "Unique identifier of the user (UUID)."
      },
      "measurementType": {
        "type": "object",
        "description": "Details about the type of measurement taken.",
        "properties": {
          "typeValue": {
            "type": "integer",
            "description": "The numerical ID representing the measurement type (e.g., 1 for Weight, 4 for Height)."
          },
          "typeDescription": {
            "type": "string",
            "description": "A human-readable description of the measurement type (e.g., 'Weight')."
          }
        },
        "required": ["typeValue", "typeDescription"]
      },
      "attrib": {
        "type": "integer",
        "description": "Attribute status of the measurement (e.g., 0 for normal, 2 for user-assigned)."
      },
      "measurementDateTime": {
        "type": "string",
        "format": "date-time",
        "description": "The UTC date and time when the measurement was taken."
      },
      "createdDateTime": {
        "type": "string",
        "format": "date-time",
        "description": "The UTC date and time when the record was created in the system."
      },
      "modifiedDateTime": {
        "type": "string",
        "format": "date-time",
        "description": "The UTC date and time when the record was last modified."
      },
      "measurementValue": {
        "type": "number",
        "description": "The actual value of the measurement (e.g., 88.441)."
      }
    },
    "required": [
      "userId",
      "measurementType",
      "attrib",
      "measurementDateTime",
      "createdDateTime",
      "modifiedDateTime",
      "measurementValue"
    ]
  }
}
